#!/usr/bin/env python3
import os,sys,json,time,subprocess
def sh(c,t=25):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception as e: return "ERR:%s"%e
def psql(q,t=30):
    for pre in (["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],):
        r=subprocess.run(pre,capture_output=True,text=True,timeout=t)
        if r.returncode==0: return r.stdout.strip()
    return "ERR"
out={"kind":"enrich_diag","ts":int(time.time())}
try:
    out["pool_active"]=sh("systemctl list-units 'atlas-enrich-pool@*.service' --state=active --no-legend --plain 2>/dev/null | wc -l")
    out["pool_enabled"]=sh("systemctl list-unit-files 'atlas-enrich-pool@*.service' 2>/dev/null | grep -c enabled")
    out["async_active"]=sh("systemctl list-units 'atlas-enrich-async*' --no-legend --plain 2>/dev/null | awk '{print $1,$4}'")
    out["one_status"]=sh("systemctl status atlas-enrich-pool@1.service --no-pager -l 2>&1 | tail -8")
    out["one_journal"]=sh("journalctl -u atlas-enrich-pool@1.service -n 15 --no-pager 2>&1 | tail -15")
    out["queue"]=psql("SELECT 'claimed='||count(*) FILTER (WHERE status='claimed')||' pending='||count(*) FILTER (WHERE status='pending')||' done='||count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
    out["queue_total"]=psql("SELECT count(*) FROM atlas.enrich_queue")
    out["pg_conns"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["enrich_conns"]=psql("SELECT count(*) FROM pg_stat_activity WHERE application_name ILIKE '%enrich%' OR query ILIKE '%enrich_queue%'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/enrich-diag.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"enrich_diag","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
